-- MASS clinic re-ingestion (FULL REPLACE, preserved codes, unit-level).
-- Generated from DRX-DATA 2026-06. 1760 units across 27 bins.
-- Review, then run via the Supabase SQL editor / MCP. Transactional.
BEGIN;

-- 1. Ensure the specialty-bin locations exist for this clinic.

-- 2. Remove the clinic's current items (FK order: cart_items, transactions, items).
DELETE FROM cart_items   WHERE item_id IN (SELECT i.id FROM items i JOIN locations l ON i.location_id = l.id WHERE l.clinic_id = 'f6e0c90c-1d7a-4257-a11f-bd1da860bcd2');
DELETE FROM transactions WHERE item_id IN (SELECT i.id FROM items i JOIN locations l ON i.location_id = l.id WHERE l.clinic_id = 'f6e0c90c-1d7a-4257-a11f-bd1da860bcd2');
DELETE FROM items        WHERE id      IN (SELECT i.id FROM items i JOIN locations l ON i.location_id = l.id WHERE l.clinic_id = 'f6e0c90c-1d7a-4257-a11f-bd1da860bcd2');

-- 3. Insert 1760 unit-level items with preserved codes.





-- 4. Reset code counters for this clinic so future check-ins start fresh.
DELETE FROM code_counters WHERE location_code IN (SELECT code FROM locations WHERE clinic_id = 'f6e0c90c-1d7a-4257-a11f-bd1da860bcd2');

-- 5. Sanity check (should report the inserted count); then COMMIT or ROLLBACK.
SELECT count(*) AS inserted FROM items i JOIN locations l ON i.location_id = l.id WHERE l.clinic_id = 'f6e0c90c-1d7a-4257-a11f-bd1da860bcd2';
COMMIT;
